/**
 * The metadata of a unit.
 */
export interface Unit {
    /**
     * A short description of the unit.
     */
    description?: string;
    /**
     * The display name of the unit.
     */
    displayName?: string;
    /**
     * The plural display name of the unit.
     */
    displayNamePlural?: string;
    /**
     * The symbol of the unit.
     */
    symbol?: string;
    /**
     * The ID of the unit.
     */
    unitId: string;
}
